const match = allCompanies.find(c =>
  c.name.trim().toLowerCase() === selected
);

if (!match) {
  return {
    json: { error: "Company not found", selected }
  };
}

match.firstName = $json.body.firstName;
match.email = $json.body.email;

return {
  json: match
};

options.systemMessage:
=You are the Company Context Builder Agent for a Venture Capital.

Your job is to extract and format all the key facts about this startup for downstream agents.

Here is the structured JSON data:
- Name: {{ $json.name }}
- Sector: {{ $json.sector }}
- Website: {{ $json.website }}
- Headquarters: {{ $json.hq }}
- Founded: {{ $json.founded }}
- First Investment: {{ $json.first_investment }}
- Founders: {{ $json.founders.join(", ") }}
- Description: {{ $json.description }}

Your Output:
Summarize this into a clear, well-formatted paragraph that future agents can read quickly.
Avoid unnecessary repetition. Be neutral in tone.

* Include that the VC has invested on that startup.

Return only the paragraph.

parameters.text:
=Using:
