function basicMarkdownToHTML(md) {
  return md
    // headings
    .replace(/^#### (.*)$/gm, '<h5 style="margin-top: 20px; margin-bottom: 5px;">$1</h5>')
    .replace(/^### (.*)$/gm, '<h4 style="margin-top: 20px; margin-bottom: 5px;">$1</h4>')
    .replace(/^## (.*)$/gm, '<h3 style="margin-top: 25px; margin-bottom: 10px; color: #333;">$1</h3>')
    .replace(/^# (.*)$/gm, '<h3 style="margin-top: 30px; margin-bottom: 10px; color: #222;">$1</h3>')
    // bold text
    .replace(/\*\*(.*?)\*\*/g, '<strong>$1</strong>')
    // Italics
    .replace(/\*(.*?)\*/g, '<span style="font-style: italic">$1</span>')
    // numbered lists
    .replace(/^\d+\. (.*)$/gm, '<li>$1</li>')
    // unordered lists
    .replace(/^- (.*)$/gm, '<li>$1</li>')
    // wrap standalone <li> with <ul> or <ol> later
    .replace(/(<li>.*<\/li>)/g, '<ul>$1</ul>')
    .replace(/\n{2,}/g, '<br><br>') // double newlines as spacing

    // Format Links
    .replace(/\[([^\]]+)\]\((https?:\/\/[^\s)]+)\)/g, '<a href="$2" target="_blank" style="color: #0066cc;">$1</a>')

}

