Return ONLY the JSON per the schema. Minimum 10 solid sources, at least 2 for funding activity databases, and at least 1 regulatory source if applicable.

parameters.jsCode:
const root = $input.first().json.companyInfo
const payload = root.payload;
const companyId = String(payload.company?.id ?? "").trim();
const base = 'https://publicity.businessportal.gr';

if (!companyId) throw new Error('Δεν βρέθηκε companyId');

const modIds = (payload.ModificationHistoryData ?? [])
  .map(x => x?.id)
  .filter(Boolean);

const finIds = [];
for (const period of (payload.companyFinancial ?? [])) {
  for (const fa of (period?.FilesAndAuditors ?? [])) {
    for (const b of (fa?.balancesheet ?? [])) {
      if (b?.id != null) finIds.push(b.id);
    }
  }
}

// Φτιάχνουμε τα URLs
const items = [];

// Modifications
for (const id of modIds) {
  items.push({
    json: {
      kind: 'modification',
      id: String(id),
      url: `${base}/api/download/Modifications/${id}?companyId=${companyId}`
    }
  });
}

// Financial
for (const id of finIds) {
  items.push({
    json: {
      kind: 'financial',
      id: Number(id),
      url: `${base}/api/download/financial/${id}?companyId=${companyId}`
    }
  });
}

return items;

// Πάρε όλα τα texts από τα items
const texts = items.map(i => i.json.text || i.json.body || '');

// Πρώτα 10 -> modification
let modificationText = texts.slice(0, 10).join("\n\n");

// Τελευταία 10 -> financial
let financialText = texts.slice(-10).join("\n\n");

// Καθάρισε τα πολλαπλά newlines -> μόνο ένα
modificationText = modificationText.replace(/(\n\s*\n)+/g, '\n');
financialText = financialText.replace(/(\n\s*\n)+/g, '\n');

// Καθάρισε τα πολλαπλά spaces -> το πολύ δύο
modificationText = modificationText.replace(/ {3,}/g, '  ');
financialText = financialText.replace(/ {3,}/g, '  ');

// Καθάρισε τα spaces μετά από newline -> κράτα μόνο το \n
modificationText = modificationText.replace(/\n +/g, '\n');
financialText = financialText.replace(/\n +/g, '\n');

// Επιστροφή ενός αντικειμένου
return [
  {
    json: {
      modification: modificationText,
      financial: financialText
    }
  }
];

